onClick:
{{
  save_manual_cn.run()
    .then(() => {
      showAlert('Credit Note Created Successfully!', 'success');
      // Clear the table and invoice selection
      resetWidget("selInvoice");
      resetWidget("tblCreditLines");
      resetWidget("iptFlatAmount");
      storeValue('GlobalCreditLinesData', []);
      // Refresh the existing returns list to see the new entry
      get_existing_returns.run();
    })
    .catch((err) => {
      showAlert('Failed to save Credit Note: ' + save_manual_cn.data.error, 'error');
    })
}}
